/**
 * Calculates a property's resilience score against extreme weather events.
 * The score is based on construction materials, design, maintenance, and local climate risks.
 * The formula combines base scores for structural elements with modifiers for year of construction
 * and maintenance quality, then applies penalties based on the mismatch between features and local risks.
 *
 * @param {object} inputs - An object containing all input values.
 * @param {string} inputs.buildingType - Type of building (e.g., 'residential_single_family').
 * @param {number} inputs.constructionYear - Year the building was constructed.
 * @param {string} inputs.structuralMaterial - Primary structural material (e.g., 'reinforced_concrete').
 * @param {string} inputs.roofSystem - Type of roof system (e.g., 'pitched_metal').
 * @param {string} inputs.foundationType - Type of foundation (e.g., 'elevated_pier_piles').
 * @param {string} inputs.openingProtection - Level of protection for windows and doors (e.g., 'impact_rated_windows_doors').
 * @param {string} inputs.maintenanceQuality - Quality of building maintenance (e.g., 'good').
 * @param {string} inputs.floodRiskLevel - Local flood risk level (e.g., 'high').
 * @param {string} inputs.windRiskLevel - Local wind risk level (e.g., 'very_high').
 * @returns {object} An object containing the resilienceScore (0-100) and vulnerabilityRating (string).
 */
function calculateResilienceScore(inputs) {
  let score = 0;

  // Base points for building type
  switch (inputs.buildingType) {
    case 'residential_single_family': score += 5; break;
    case 'multi_family_low_rise': score += 8; break;
    case 'commercial_light': score += 10; break;
    case 'commercial_heavy': score += 12; break;
    case 'industrial': score += 10; break;
  }

  // Points for construction year (reflecting code evolution)
  if (inputs.constructionYear < 1980) {
    score -= 10;
  } else if (inputs.constructionYear >= 1980 && inputs.constructionYear <= 2000) {
    score -= 5;
  } else if (inputs.constructionYear > 2000 && inputs.constructionYear <= 2015) {
    score += 5;
  } else if (inputs.constructionYear > 2015) {
    score += 10;
  }

  // Points for structural material
  switch (inputs.structuralMaterial) {
    case 'unreinforced_masonry': score -= 10; break;
    case 'wood_frame_standard': score += 0; break; // Baseline
    case 'wood_frame_advanced': score += 5; break;
    case 'structural_steel': score += 10; break;
    case 'reinforced_concrete': score += 15; break;
  }

  // Points for roof system
  switch (inputs.roofSystem) {
    case 'pitched_shingle_standard': score += 0; break;
    case 'flat_ballasted': score += 3; break;
    case 'pitched_metal': score += 7; break;
    case 'pitched_tile': score += 8; break;
    case 'flat_adhered_mechanically': score += 10; break;
  }

  // Points for foundation type
  switch (inputs.foundationType) {
    case 'slab_on_grade': score += 0; break;
    case 'crawl_space_vented': score += 2; break;
    case 'full_basement': score += 5; break;
    case 'elevated_pier_piles': score += 10; break;
  }

  // Points for opening protection
  switch (inputs.openingProtection) {
    case 'standard_windows_doors': score += 0; break;
    case 'reinforced_windows_doors': score += 5; break;
    case 'impact_rated_windows_doors': score += 10; break;
    case 'hurricane_shutters': score += 15; break;
  }

  // Points for maintenance quality
  switch (inputs.maintenanceQuality) {
    case 'poor': score -= 10; break;
    case 'average': score += 0; break;
    case 'good': score += 5; break;
    case 'excellent': score += 10; break;
  }

  // --- Risk Penalties (Conditional Logic) ---

  // Flood Risk Penalties
  if (inputs.floodRiskLevel === 'moderate') {
    if (inputs.foundationType === 'slab_on_grade' || inputs.foundationType === 'crawl_space_vented') score -= 5;
  } else if (inputs.floodRiskLevel === 'high') {
    if (inputs.foundationType === 'slab_on_grade' || inputs.foundationType === 'crawl_space_vented') score -= 15;
    if (inputs.foundationType === 'full_basement') score -= 10;
  } else if (inputs.floodRiskLevel === 'very_high') {
    if (inputs.foundationType === 'slab_on_grade' || inputs.foundationType === 'crawl_space_vented' || inputs.foundationType === 'full_basement') score -= 25;
  }

  // Wind Risk Penalties
  if (inputs.windRiskLevel === 'moderate') {
    if (inputs.roofSystem === 'pitched_shingle_standard') score -= 5;
    if (inputs.openingProtection === 'standard_windows_doors') score -= 5;
  } else if (inputs.windRiskLevel === 'high') {
    if (inputs.roofSystem === 'pitched_shingle_standard' || inputs.roofSystem === 'flat_ballasted') score -= 15;
    if (inputs.openingProtection === 'standard_windows_doors' || inputs.openingProtection === 'reinforced_windows_doors') score -= 10;
  } else if (inputs.windRiskLevel === 'very_high') {
    if (inputs.roofSystem === 'pitched_shingle_standard' || inputs.roofSystem === 'flat_ballasted') score -= 25;
    if (inputs.openingProtection === 'standard_windows_doors' || inputs.openingProtection === 'reinforced_windows_doors') score -= 15;
  }

  // Cap the score between 0 and 100
  let resilienceScore = Math.max(0, Math.min(100, score));

  // Determine vulnerability rating
  let vulnerabilityRating;
  if (resilienceScore >= 80) {
    vulnerabilityRating = 'Very Low Vulnerability';
  } else if (resilienceScore >= 60) {
    vulnerabilityRating = 'Low Vulnerability';
  } else if (resilienceScore >= 40) {
    vulnerabilityRating = 'Moderate Vulnerability';
  } else if (resilienceScore >= 20) {
    vulnerabilityRating = 'High Vulnerability';
  } else {
    vulnerabilityRating = 'Very High Vulnerability';
  }

  return {
    resilienceScore: resilienceScore,
    vulnerabilityRating: vulnerabilityRating
  };
}
